window.__QUIZ_DATA__=[{"id":"theory>Economics>2019>1>a>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"The diagram below represents the equilibrium position of a firm in a perfectly competitive industry.  Study it carefully and answer this question      At what level of output and price is the firm in equilibrium?","images":["data:image/png;base64,"],"marking_scheme":"The firm equilibrium is a point when the MC = MR which is a perfect market.  At an output level of 50kg and price level of $20 is the firm equilibrium.","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>1>a>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"FINAL","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"The diagram below represents the equilibrium position of a firm in a perfectly competitive industry.  Study it carefully and answer this question    Calculate the firm Y profit in equilibrium.","images":["data:image/png;base64,"],"marking_scheme":"The firm's profit in equilibrium is the difference between total revenue and total cost.  Profit = TR - TC  TR = P \u00d7 Q  \u21d2 20 \u00d7 50  \u21d2 $1,000    *therefore* TC = AC \u00d7 Q  \u21d2 10 \u00d7 40  \u21d2 400    *therefore* Profit = TR - TC  \u21d2 1000 - 400 = $600","marks":"4","difficulty":"3"},{"id":"theory>Economics>2019>1>a>iii","subject":"Economics","year":"2019","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"The diagram below represents the equilibrium position of a firm in a perfectly competitive industry.  Study it carefully and answer this question    The firm makes what type of profit?","images":["data:image/png;base64,"],"marking_scheme":"The profit is abnormal profit. This is because a perfect competitor makes abnormal profit in the short-run.","marks":"3","difficulty":"3"},{"id":"theory>Economics>2019>1>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"The diagram below represents the equilibrium position of a firm in a perfectly competitive industry.  Study it carefully and answer this question      Why is the average revenue (AR) function horizontal?","images":["data:image/png;base64,"],"marking_scheme":"The average revenue (AR) function is horizontal because the firm is a perfect market since the AR is also the Price.","marks":"3","difficulty":"3"},{"id":"theory>Economics>2019>1>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"MARKET STRUCTURE : PERFECT MARKET","question":"The diagram below represents the equilibrium position of a firm in a perfectly competitive industry.  Study it carefully and answer this question    State any two ways in which marginal cost (MC) and average total cost (ATC) are related.","images":["data:image/png;base64,","data:image/png;base64,"],"marking_scheme":"- Both the marginal cost and the average total cost are \"U-shape\"    - Mc cuts ATC/AC at the lowest or minimum level. The point where MC cuts the ATC curve is minimum efficient scale point     - MC is factored into the ATC at every unit","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>2>a","subject":"Economics","year":"2019","type":"Theory","sub_label":"a","group":"FINAL","topic":"INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT","question":"The extract from a country's balance of payments account. It shown below.  ITEMIMPORT (3 million)EXPORT (3 million)Agricultural product  Mineral products  Consumer goods  Capital goods  Insurance  Banking  Transportation  Loans -   -  250  400  50  75  85  150200  300  -  -  25  30  25  60  Using the table above, calculate the    balance of trade.","images":[],"marking_scheme":"balance of trade = visible export - visible import   Visible export($m)($m)Agricultural products  Mineral products     200  300  500less: visible importconsumer products   capital products50  400  (650)(150) (Unfavourable)","marks":"8","difficulty":"2"},{"id":"theory>Economics>2019>2>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"FINAL","topic":"INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT","question":"The extract from a country's balance of payments account. It shown below.  ITEMIMPORT (3 million)EXPORT (3 million)Agricultural product  Mineral products  Consumer goods  Capital goods  Insurance  Banking  Transportation  Loans -   -  250  400  50  75  85  150200  300  -  -  25  30  25  60  Using the table above, calculate the   invisible trade balance.","images":[],"marking_scheme":"Invisible trade balance = Invisible export - Invisible import.  Invisible export($m)($m)Insurance  Banking   Transportation    25  30  2580less: Invisible importInsurance  Banking   Transportation50  75  85    (210)(130)","marks":"6","difficulty":"2"},{"id":"theory>Economics>2019>2>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"FINAL","topic":"INTERNATIONAL TRADE : BALANCE OF TRADE & PAYMENT","question":"The extract from a country's balance of payments account. It shown below.  ITEMIMPORT (3 million)EXPORT (3 million)Agricultural product  Mineral products  Consumer goods  Capital goods  Insurance  Banking  Transportation  Loans -   -  250  400  50  75  85  150200  300  -  -  25  30  25  60  Using the table above, calculate the   balance on current account.","images":[],"marking_scheme":"Balance on current account = Total visible and Invisible Export - Total visible and Invisible Import.        Total Export = 200+300 + 25+30+25  \u21d2 $580    Total Import = 250+400+50+75+85  \u21d2 $860    Balance on current account = $580 - $860  \u21d2 ($280)","marks":"6","difficulty":"2"},{"id":"theory>Economics>2019>3>a>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : INTRODUCTION","question":"Define distribution of goods.","images":[],"marking_scheme":"Distribution of goods: This is the process of making a product or service available for the consumer or business user who need it. This can be done directly by the producer or service provider or indirect channels with distributors or intermediaries.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2019>3>a>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"DISTRIBUTIVE TRADE : INTRODUCTION","question":"Illustrate the normal chain of distribution of goods.","images":[],"marking_scheme":"Normal distribution of goods is illustrated below;  Producer \u2192 Wholesaler \u2192 Retailer \u2192 Consumer","marks":"5","difficulty":"2"},{"id":"theory>Economics>2019>3>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES","question":"Describe a consumers' cooperative society.","images":[],"marking_scheme":"Consumer's cooperative society is a cooperative business owned by its customers for their mutual benefit. It is a form of free enterprise that is oriented toward service rather than pecuniary profit","marks":"3","difficulty":"2"},{"id":"theory>Economics>2019>3>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : CO-OPERATIVE SOCIETIES","question":"Outline any four roles performed by a consumers' cooperative society.","images":[],"marking_scheme":"- To enlighten members or educate members  - To sell quality goods or services at a reasonable price.  - To ensure that the goods are sold with good measure and weight.  - To help the government in distribution policy especially during the period of scarcity  - To safeguard members from exploitation.","marks":"7","difficulty":"2"},{"id":"theory>Economics>2019>4>a","subject":"Economics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"INDUSTRY & INDUSTRIALISATION : INTRODUCTION","question":"What is an industry?","images":[],"marking_scheme":"Industry is concerned with the coming together of two or more firms that produce similar goods or render similar services in an economy. It is an economic activity concerned with the processing of raw materials and manufacturing of goods in factories.","marks":"5","difficulty":"1"},{"id":"theory>Economics>2019>4>b>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : DIVISION OF LABOUR & SPECIALISATION","question":"Explain division of labour.","images":[],"marking_scheme":"Division of labour is the separation of tasks in any system so that participants may specialize. It is also the separation of a work process into a number of tasks, with each task performed by a separate person or group of persons.","marks":"3","difficulty":"2"},{"id":"theory>Economics>2019>4>b>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION","question":"Explain economics of scale.","images":[],"marking_scheme":"Economics of scale are cost advantages that enterprises obtain due to their scale of operation which is measured by amount of output produced with cost per unit of output decreasing with increasing scale.","marks":"7","difficulty":"2"},{"id":"theory>Economics>2019>4>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"THEORY OF PRODUCTION (1) : SCALE OF PRODUCTION","question":"Outline any four internal economics of scale.","images":[],"marking_scheme":"- Administrative or managerial economies    - Technical Economies    - Marketing Economies    - Financial Economies","marks":"5","difficulty":"2"},{"id":"theory>Economics>2019>5>a","subject":"Economics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : PARTNERSHIP","question":"Define a joint venture.","images":[],"marking_scheme":"Joint venture is a business arrangement in which two or more parties agree to pool their resources for the purpose of accomplishing a specific task. This task may be a new project or any other business activity","marks":"7.5","difficulty":"2"},{"id":"theory>Economics>2019>5>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : LIMITED LIABILITY COMPANIES","question":"Identify any three merits of a private company over a partnership.","images":[],"marking_scheme":"- Limited liability: Private company has separate legal entity while partnership lack limited liability.    - Improve business credibility: Registering private company improve credibility of business compared to partnership.    - Financial assistant: private company can easily get financial assistant from financial institution while partnership cannot.    - Death of member: The death of a member of a private company may not lead to the end of the company while the death of an active partner will lead to the end of the partnership business.","marks":"7.5","difficulty":"3"},{"id":"theory>Economics>2019>5>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"BUSINESS ORGANISATION : PUBLIC CORPORATIONS","question":"State any three sources of finance to a public enterprise.","images":[],"marking_scheme":"- loan from financial institution (internal or external)  - direct government finance  - re-invested cashflows","marks":"5","difficulty":"2"},{"id":"theory>Economics>2019>6>a>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Distinguish between this pair of concepts:  elastic demand and inelastic demand.","images":[],"marking_scheme":"Elastic Demand:  When demand is elastic, a small change in price leads to a significant change in the quantity demanded. This means consumers are highly responsive to price changes. If the price of a product increases, consumers will buy significantly less of it, and if the price decreases, they will buy significantly more.  Example: Luxury goods, such as designer clothing or high-end electronics, often have elastic demand because consumers can easily choose not to buy them or find substitutes if the price rises.  Inelastic Demand:    When demand is inelastic, changes in price have little effect on the quantity demanded. This means consumers are less sensitive to price changes. Even if the price increases or decreases, the quantity demanded remains relatively stable.  Example: Essential goods, such as basic food items, gasoline, or prescription medications, typically have inelastic demand because consumers need them regardless of price changes.","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>6>a>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE THEORY OF DEMAND : ELASTICITY OF DEMAND","question":"Distinguish between this pair of concepts:  income elasticity of demand and cross elasticity of demand.","images":[],"marking_scheme":"Income elasticity of demand measures the responsiveness of the quantity demanded for a good or service to a change in income. It is calculated as the ratio of the percentage change in quantity demanded to the percentage change in income     while cross elasticity of demand measures the responsiveness of the quantity demanded for a good to change in the price of another good, ceteris paribus.","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>6>b>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : APPLICATION OF ELASTICITY ON REVENUE","question":"Using diagrams, explain how an increase in price will affect the total revenue of a producer if demand for his product is price elastic.","images":["data:image/png;base64,"],"marking_scheme":"Price elastic: increase in price causes a decrease in total revenue, then demand can be said to be elastic, since the increase in price has a large impact on quantity demanded. This is shown in the diagram below;","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>6>b>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"THE CONCEPT OF COST & REVENUE : APPLICATION OF ELASTICITY ON REVENUE","question":"Using diagrams, explain how an increase in price will affect the total revenue of a producer if demand for his product is price inelastic.","images":["data:image/png;base64,"],"marking_scheme":"Price inelastic: Increase in price causes an increase in total revenue, then demand can be said to be inelastic, since the increase in price has a smaller impact on quantity demanded. This is shown in the diagram below;","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>7>a>i","subject":"Economics","year":"2019","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"POPULATION : OVER POPULATION, UNDER POPULATION","question":"Distinguish between a growing population and a declining population.","images":[],"marking_scheme":"A growing population refers to increase in the size of a population which can be either positive or negative overtime, depending on the balance of births and deaths     while     A declining population refers to a reduction in a human population caused by events such as long-term demographic trends, as in sub-replacement fertility, urban decay or other catastrophes.","marks":"7.5","difficulty":"2"},{"id":"theory>Economics>2019>7>a>ii","subject":"Economics","year":"2019","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"POPULATION : OVER POPULATION, UNDER POPULATION","question":"Distinguish between overpopulation and underpopulation.","images":[],"marking_scheme":"Overpopulation is an undesirable condition where the number of existing human population exceeds the carrying capacity of Earth resources. While underpopulation is having a lower population density than normal or desirable. The available resources is more than the human population.    Over population is also refers to human population after the optimum population while under population is refers to human population before the optimum population.","marks":"7.5","difficulty":"2"},{"id":"theory>Economics>2019>7>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"POPULATION : OVER POPULATION, UNDER POPULATION","question":"Explain any four disadvantages of a rapidly growing population in an economy.","images":[],"marking_scheme":"Disadvantages of a rapidly growing population in an economy is stated below;  - Insecurity in the country  - High crime rate in the country  - Low per capita income  - High cost of living  - Low standard of living.","marks":"5","difficulty":"3"},{"id":"theory>Economics>2019>8>a","subject":"Economics","year":"2019","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PUBLIC FINANCE : BUDGET","question":"What is public debt?","images":[],"marking_scheme":"Public debt, also known as national debt, refers to the total amount of money that a government owes to external and internal creditors. This debt is accumulated when a government borrows funds to cover budget deficits, finance public projects, or stimulate economic growth. Public debt can be incurred domestically through the issuance of government bonds or loans from local financial institutions, or externally by borrowing from foreign governments, international organizations like the International Monetary Fund (IMF), or global financial markets.","marks":"10","difficulty":"1"},{"id":"theory>Economics>2019>8>b","subject":"Economics","year":"2019","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"PUBLIC FINANCE : BUDGET","question":"Outline any three reasons why countries borrow.","images":[],"marking_scheme":"- To finance a project in the country  - To develop the economy or provision of social amenities  - To correct balance of payment deficit  - To ensure security of the citizens  - To provide for the welfare of the citizens","marks":"5","difficulty":"2"},{"id":"theory>Economics>2019>8>c","subject":"Economics","year":"2019","type":"Theory","sub_label":"c","group":"CLOSENESS","topic":"PUBLIC FINANCE : BUDGET","question":"Highlight any three effects of a huge national debt on the economy of a country.","images":[],"marking_scheme":"- Its drag GDP growth  - Lower national savings and income higher  - Negative effect on economic growth  - Balance of payment deficit  - Trade imbalance","marks":"5","difficulty":"2"}];